sql:
SELECT assets.asset_name, asset_status.status_name
FROM assets
INNER JOIN asset_status ON assets.status = asset_status.status_id;

SELECT assets.asset_name, locations.location_name
FROM assets
INNER JOIN locations ON assets.location_id = locations.location_id;

external_knowledge:
- "treasures" refers to assets;
- "paths" refers to the models of the assets;
- "haven" refers to the locations where the assets are deployed;
- "guardians" metaphorically refers to the status of the assets;
- "tales that these treasures speak in the halls of time" refers to the historical significance or the stories and conditions these assets represent, linked to their status and location.

sql:
SELECT asset_name, battery_life 
FROM assets 
WHERE battery_life > (SELECT AVG(battery_life) FROM assets);

external_knowledge:
- 'person in charge' refers to the user who deployed the asset;
- 'emergency placements' implies the deployment reason is 'Emergency deployment';
- 'sensors intended for immediate use' indicates the asset type is 'Sensor A'.

sql:
SELECT DISTINCT a.asset_id 
FROM assets a 
JOIN asset_maintenance am ON a.asset_id = am.asset_id;

SELECT asset_id, asset_name
FROM assets
WHERE asset_id NOT IN (SELECT asset_id FROM asset_deployments);

SELECT maintenance_type, description, maintenance_time, maintenance_cost
FROM asset_maintenance
WHERE asset_id = 2;

SELECT AVG(value) AS average_air_value
FROM asset_samples
WHERE sample_type = 'air';

SELECT log_type, COUNT(DISTINCT asset_id) AS asset_count
FROM asset_logs
GROUP BY log_type;
